    "content": "/* Minimal RequireJS CSS loader plugin for PCI runtime. */\ndefine(function () {\n  \"use strict\";\n\n  var head = document.getElementsByTagName(\"head\")[0];\n\n  function normalize(name) {\n    if (!name) return name;\n    return name.endsWith(\".css\") ? name : name + \".css\";\n  }\n\n  return {\n    load: function (name, req, onload) {\n      try {\n        var url = req.toUrl(normalize(name));\n        var link = document.createElement(\"link\");\n        link.type = \"text/css\";\n        link.rel = \"stylesheet\";\n        link.href = url;\n        link.onload = function () {\n          onload();\n        };\n        link.onerror = function () {\n          if (onload && typeof onload.error === \"function\") {\n            onload.error(new Error(\"Failed to load CSS: \" + url));\n          } else {\n            onload();\n          }\n        };\n        head.appendChild(link);\n      } catch (err) {\n        if (onload && typeof onload.error === \"function\") {\n          onload.error(err);\n        } else {\n          onload();\n        }\n      }\n    },\n  };\n});\n"
