    "path": "modules/legacyPortableSharedLib/OAT/util/EventMgr.js",
    "content": "define([\"OAT/lodash\"], function (_) {\n  \"use strict\";\n\n  return function EventMgr() {\n    var events = {};\n\n    this.get = function get(event) {\n      if (event && events[event]) {\n        return _.clone(events[event]);\n      } else {\n        return [];\n      }\n    };\n\n    this.on = function on(event, callback) {\n      var name;\n      var tokens = event.split(\".\");\n      if (tokens[0]) {\n        name = tokens.shift();\n        events[name] = events[name] || [];\n        events[name].push({\n          ns: tokens,\n          callback: callback,\n        });\n      }\n    };\n\n    this.off = function off(event) {\n      if (event && events[event]) {\n        events[event] = [];\n      }\n    };\n\n    this.trigger = function trigger(event, data) {\n      if (events[event]) {\n        _.forEach(events[event], function (e) {\n          e.callback.apply(\n            {\n              type: event,\n              ns: [],\n            },\n            data,\n          );\n        });\n      }\n    };\n  };\n});\n"
